1266→  /**
1267→   * Strategy Pattern: Determine if a folder can be dragged
1268→   * Single Responsibility Principle: Separate logic for draggability check
1269→   *
1270→   * A folder can be dragged if and only if:
1271→   * - It has no subfolders (to prevent deep nesting complexity)
1272→   *
1273→   * @param folderId - The ID of the folder to check
1274→   * @returns true if the folder can be dragged, false otherwise
1275→   */
1276→  private canFolderBeDragged(folderId: string): boolean {
1277→    return !this.data.folders.some((f) => f.parentId === folderId);
1278→  }
1279→
1280→  /**
1281→   * Strategy Pattern: Apply or remove draggable behavior based on folder state
1282→   * Open/Closed Principle: Easy to extend with new draggable conditions
1283→   *
1284→   * This method ensures that folder draggability is always in sync with the current state.
1285→   * It will enable dragging if conditions are met, or disable it if not.
1286→   *
1287→   * @param element - The folder header element
1288→   * @param folder - The folder data object
1289→   */
1290→  private applyFolderDraggableBehavior(element: HTMLElement, folder: Folder): void {
1291→    if (this.canFolderBeDragged(folder.id)) {
1292→      this.enableFolderDragging(element, folder);
1293→    } else {
1294→      this.disableFolderDragging(element);
1295→    }
1296→  }
