1298→  /**
1299→   * Enable dragging for a folder element
1300→   * Encapsulates all logic needed to make a folder draggable
1301→   *
1302→   * Uses a data attribute to track drag listeners and prevent duplicates.
1303→   * This ensures event listeners are only added once per element lifecycle.
1304→   *
1305→   * @param element - The folder header element
1306→   * @param folder - The folder data object
1307→   */
1308→  private enableFolderDragging(element: HTMLElement, folder: Folder): void {
1309→    // Mark element as draggable
1310→    element.draggable = true;
1311→    element.style.cursor = 'grab';
1312→
1313→    // Check if drag listeners are already attached
1314→    if (element.dataset.dragListenersAttached === 'true') {
1315→      this.debug('Drag listeners already attached for folder:', folder.name);
1316→      return;
1317→    }
1318→
1319→    // Create named event handler functions for proper cleanup
1320→    const handleDragStart = (e: Event) => {
1321→      e.stopPropagation(); // Prevent parent folder from being dragged
1322→
1323→      const dragData: DragData = {
1324→        type: 'folder',
1325→        folderId: folder.id,
1326→        title: folder.name,
1327→      };
1328→
1329→      const dt = (e as DragEvent).dataTransfer;
1330→      if (dt) dt.effectAllowed = 'move';
1331→      dt?.setData('application/json', JSON.stringify(dragData));
1332→      element.style.opacity = '0.5';
1333→
1334→      this.debug(
1335→        'Folder drag start:',
1336→        folder.name,
1337→        'canBeDragged:',
1338→        this.canFolderBeDragged(folder.id),
1339→      );
1340→    };
1341→
1342→    const handleDragEnd = () => {
1343→      element.style.opacity = '1';
1344→    };
1345→
1346→    // Store references for potential cleanup
1347→    type DragEl = Element & {
1348→      _dragStartHandler?: (e: Event) => void;
1349→      _dragEndHandler?: () => void;
1350→    };
1351→    (element as DragEl)._dragStartHandler = handleDragStart;
1352→    (element as DragEl)._dragEndHandler = handleDragEnd;
1353→
1354→    // Add drag event listeners
1355→    element.addEventListener('dragstart', handleDragStart);
1356→    element.addEventListener('dragend', handleDragEnd);
1357→
1358→    // Mark that listeners are attached
1359→    element.dataset.dragListenersAttached = 'true';
1360→  }
1361→
1362→  /**
1363→   * Disable dragging for a folder element
1364→   * Ensures folder cannot be dragged when it has subfolders
1365→   *
1366→   * Properly removes event listeners to prevent memory leaks.
1367→   *
1368→   * @param element - The folder header element
1369→   */
1370→  private disableFolderDragging(element: HTMLElement): void {
1371→    element.draggable = false;
1372→    element.style.cursor = '';
1373→
1374→    // Remove drag event listeners if they exist
1375→    if (element.dataset.dragListenersAttached === 'true') {
1376→      type DragEl = Element & {
1377→        _dragStartHandler?: (e: Event) => void;
1378→        _dragEndHandler?: () => void;
1379→      };
1380→      const dragStartHandler = (element as DragEl)._dragStartHandler;
1381→      const dragEndHandler = (element as DragEl)._dragEndHandler;
1382→
1383→      if (dragStartHandler) {
1384→        element.removeEventListener('dragstart', dragStartHandler);
1385→        delete (element as DragEl)._dragStartHandler;
1386→      }
1387→
1388→      if (dragEndHandler) {
1389→        element.removeEventListener('dragend', dragEndHandler);
1390→        delete (element as DragEl)._dragEndHandler;
1391→      }
1392→
1393→      delete element.dataset.dragListenersAttached;
1394→    }
1395→  }
