2294→      const bIdx = b.sortIndex ?? -1;
2295→      if (aIdx >= 0 && bIdx >= 0) return aIdx - bIdx;
2296→
2297→      // Fall back to name-based sort
2298→      return a.name.localeCompare(b.name, undefined, {
2299→        numeric: true,
2300→        sensitivity: 'base',
2301→      });
2302→    });
