2725→  private addFolderToFolder(targetFolderId: string, dragData: DragData): void {
2726→    const draggedFolderId = dragData.folderId;
2727→    if (!draggedFolderId) return;
2728→
2729→    this.debug('Moving folder to folder:', {
2730→      draggedFolderId,
2731→      targetFolderId,
2732→    });
2733→
2734→    // Prevent dropping a folder onto itself
2735→    if (draggedFolderId === targetFolderId) {
2736→      this.debug('Cannot drop folder onto itself');
2737→      return;
2738→    }
2739→
2740→    // Prevent dropping a folder onto its descendant (would create a cycle)
2741→    if (this.isFolderDescendant(targetFolderId, draggedFolderId)) {
2742→      this.debug('Cannot drop folder onto its descendant');
2743→      return;
2744→    }
2745→
2746→    // Find the dragged folder
2747→    const draggedFolder = this.data.folders.find((f) => f.id === draggedFolderId);
2748→    if (!draggedFolder) return;
2749→
2750→    // Update the parent
2751→    draggedFolder.parentId = targetFolderId;
2752→    draggedFolder.updatedAt = Date.now();
2753→
2754→    this.saveData();
2755→    this.refresh();
2756→  }
