2758→  private moveFolderToRoot(dragData: DragData): void {
2759→    const draggedFolderId = dragData.folderId;
2760→    if (!draggedFolderId) return;
2761→
2762→    this.debug('Moving folder to root level:', draggedFolderId);
2763→
2764→    // Find the dragged folder
2765→    const draggedFolder = this.data.folders.find((f) => f.id === draggedFolderId);
2766→    if (!draggedFolder) return;
2767→
2768→    // If already at root level, no need to do anything
2769→    if (draggedFolder.parentId === null) {
2770→      this.debug('Folder is already at root level');
2771→      return;
2772→    }
2773→
2774→    // Update the parent to null (root level)
2775→    draggedFolder.parentId = null;
2776→    draggedFolder.updatedAt = Date.now();
2777→
2778→    this.saveData();
2779→    this.refresh();
2780→  }
