2782→  private isFolderDescendant(folderId: string, potentialAncestorId: string): boolean {
2783→    // Check if potentialAncestorId is an ancestor of folderId
2784→    let currentId: string | null = folderId;
2785→    while (currentId) {
2786→      if (currentId === potentialAncestorId) {
2787→        return true;
2788→      }
2789→      const folder = this.data.folders.find((f) => f.id === currentId);
2790→      currentId = folder?.parentId || null;
2791→    }
2792→    return false;
2793→  }
