 18→function waitForElement<T extends Element = Element>(
 19→  selector: string,
 20→  timeoutMs = 10000,
 21→): Promise<T | null> {
 22→  return new Promise((resolve) => {
 23→    const found = document.querySelector(selector) as T | null;
 24→    if (found) return resolve(found);
 25→    const obs = new MutationObserver(() => {
 26→      const el = document.querySelector(selector) as T | null;
 27→      if (el) {
 28→        try {
 29→          obs.disconnect();
 30→        } catch {}
 31→        resolve(el);
 32→      }
 33→    });
 34→    try {
 35→      obs.observe(document.body, { childList: true, subtree: true });
 36→    } catch {}
 37→    if (timeoutMs > 0) {
 38→      setTimeout(() => {
 39→        try {
 40→          obs.disconnect();
 41→        } catch {}
 42→        resolve(null);
 43→      }, timeoutMs);
 44→    }
 45→  });
 46→}
