102→export function mutationAddsPromptLinks(mutations: MutationRecord[]): boolean {
103→  for (const mutation of mutations) {
104→    for (const node of Array.from(mutation.addedNodes)) {
105→      if (nodeContainsPromptLink(node)) return true;
106→    }
107→  }
108→  return false;
109→}
110→
111→function mutationMayAffectPromptTitles(mutations: MutationRecord[]): boolean {
112→  for (const mutation of mutations) {
113→    if (mutation.type === 'characterData') {
114→      if (mutation.target.parentElement?.closest(PROMPT_LINK_SELECTOR)) return true;
115→      continue;
116→    }
117→
118→    if (mutation.type === 'attributes') {
119→      if (mutation.target instanceof Element && mutation.target.closest(PROMPT_LINK_SELECTOR))
120→        return true;
121→      continue;
122→    }
123→
124→    if (mutation.type === 'childList') {
125→      if (mutation.target instanceof Element && mutation.target.closest(PROMPT_LINK_SELECTOR)) {
126→        return true;
127→      }
128→
129→      for (const node of Array.from(mutation.addedNodes)) {
130→        if (nodeContainsPromptLink(node)) return true;
131→      }
132→      for (const node of Array.from(mutation.removedNodes)) {
133→        if (nodeContainsPromptLink(node)) return true;
134→      }
135→    }
136→  }
137→  return false;
138→}
