140→function extractPromptIdFromHref(rawHref: string): string | null {
141→  const href = String(rawHref || '').trim();
142→  if (!href) return null;
143→  const match = href.match(/\/prompts\/([^/?#]+)/);
144→  if (match && match[1]) return match[1];
145→  try {
146→    const url = new URL(href, location.origin);
147→    const pathMatch = url.pathname.match(/\/prompts\/([^/?#]+)/);
148→    return pathMatch?.[1] || null;
149→  } catch {
150→    return null;
151→  }
152→}
