154→function normalizeDroppedUrl(raw: string): string | null {
155→  const firstLine = String(raw || '')
156→    .split(/\r?\n/, 1)[0]
157→    ?.trim();
158→  if (!firstLine) return null;
159→  if (/^https?:\/\//i.test(firstLine)) return firstLine;
160→  if (firstLine.startsWith('/')) return `${location.origin}${firstLine}`;
161→  return null;
162→}
