164→export function parseDragDataPayload(raw: string): DragData | null {
165→  const trimmed = String(raw || '').trim();
166→  if (!trimmed) return null;
167→
168→  try {
169→    const parsed = JSON.parse(trimmed) as unknown;
170→    if (
171→      parsed &&
172→      typeof parsed === 'object' &&
173→      (parsed as { type?: unknown }).type === 'conversation' &&
174→      typeof (parsed as { conversationId?: unknown }).conversationId === 'string'
175→    ) {
176→      const data = parsed as DragData;
177→      return {
178→        type: 'conversation',
179→        conversationId: data.conversationId,
180→        title: typeof data.title === 'string' ? data.title : '',
181→        url: typeof data.url === 'string' ? data.url : '',
182→      };
183→    }
184→  } catch {}
185→
186→  const normalizedUrl = normalizeDroppedUrl(trimmed);
187→  if (!normalizedUrl) return null;
188→  const conversationId = extractPromptIdFromHref(normalizedUrl);
189→  if (!conversationId) return null;
190→
191→  return {
192→    type: 'conversation',
193→    conversationId,
194→    title: '',
195→    url: normalizedUrl,
196→  };
197→}
