  const dragData: DragData = {
    type: 'folder',
    folderId: folder.id,
    title: folder.name,
  };
  dt?.setData('application/json', JSON.stringify(dragData));
  element.style.opacity = '0.5';
}
```

#### B. **dragover** (While dragging over targets)

**setupDropZone** (`manager.ts` lines 1117-1122):
```typescript
element.addEventListener('dragover', (e) => {
  e.preventDefault();
  e.stopPropagation();  // Block parent handlers
  if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
  element.classList.add('gv-folder-dragover');  // Visual feedback
});
```

**setupRootDropZone** (`manager.ts` lines 1176-1185):
```typescript
element.addEventListener('dragover', (e) => {
  const data = e.dataTransfer?.types.includes('application/json');
  if (!data) return;
  e.preventDefault();
  e.stopPropagation();
  if (e.dataTransfer) e.dataTransfer.dropEffect = 'move';
  element.classList.add('gv-folder-list-dragover');
});
```

**Conversation reorder zones** (`manager.ts` lines 2318-2331):
```typescript
convEl.addEventListener('dragover', (e) => {
  e.preventDefault();
  const rect = convEl.getBoundingClientRect();
  const midY = rect.top + rect.height / 2;
  const isTopHalf = e.clientY < midY;

  convEl.classList.remove('gv-reorder-above', 'gv-reorder-below');
  convEl.classList.add(isTopHalf ? 'gv-reorder-above' : 'gv-reorder-below');
});
```

#### C. **dragleave** (Exiting drop zones) - TWO DIFFERENT APPROACHES

**Approach 1: Simple removal** (`manager.ts` lines 1124-1126) - Used in setupDropZone:
```typescript
element.addEventListener('dragleave', () => {
  element.classList.remove('gv-folder-dragover');
});
```
⚠️ **Issue:** This removes highlight on ANY child exit, even temporary ones

**Approach 2: Coordinate-based** (`manager.ts` lines 1187-1196) - Used in setupRootDropZone:
```typescript
element.addEventListener('dragleave', (e) => {
  const rect = element.getBoundingClientRect();
  const x = (e as DragEvent).clientX;
  const y = (e as DragEvent).clientY;

  // Only remove if cursor is OUTSIDE element bounds
  if (x <= rect.left || x >= rect.right || y <= rect.top || y >= rect.bottom) {
    element.classList.remove('gv-folder-list-dragover');
  }
});
```
✅ **Better:** Only removes when cursor physically leaves the element

**Approach 3: Counter-based** (`aistudio.ts` lines 1264-1292) - Most robust:
```typescript
let dragEnterCounter = 0;

el.addEventListener('dragenter', (e) => {
  dragEnterCounter++;
  if (dragEnterCounter === 1) {
    el.classList.add('gv-folder-dragover');
  }
});

el.addEventListener('dragleave', (e) => {
  dragEnterCounter--;
  if (dragEnterCounter <= 0) {
    dragEnterCounter = 0;
    const related = e.relatedTarget as Node | null;
    if (!related || !el.contains(related)) {
      el.classList.remove('gv-folder-dragover');
    }
  }
});
```
✅ **Best:** Tracks nested dragenter/dragleave pairs to handle child elements correctly

#### D. **drop** (Handling the drop)

**Basic drop flow** (`manager.ts` lines 1128-1172):
```typescript
element.addEventListener('drop', (e) => {
  e.preventDefault();
  e.stopPropagation();  // CRITICAL: Prevent bubbling to parent
  element.classList.remove('gv-folder-dragover');

  const data = e.dataTransfer?.getData('application/json');
  if (!data) return;

  const dragData: DragData = JSON.parse(data);

  // Restore opacity before processing
  this.selectedConversations.forEach((id) => {
    const el = this.findConversationElement(id);
    if (el) el.style.opacity = '1';
  });

  // Route based on type
  if (dragData.type === 'folder') {
    this.addFolderToFolder(folderId, dragData);
  } else {
    if (dragData.conversations && dragData.conversations.length > 0) {
      // Multi-select
      this.addConversationsToFolder(folderId, dragData.conversations, dragData.sourceFolderId);
    } else {
      // Single
      this.addConversationToFolder(folderId, dragData);
    }
  }

  this.exitMultiSelectMode();
});
```

#### E. **dragend** (Cleanup after drag)

`manager.ts` lines 1554-1570:
```typescript
element.addEventListener('dragend', () => {
  // Restore opacity for all selected
  if (this.selectedConversations.size > 1) {
    this.selectedConversations.forEach((id) => {
      const el = this.findConversationElement(id);
      if (el) el.style.opacity = '1';
    });
  } else {
    element.style.opacity = '1';
  }

  // Exit multi-select if not in multi-select mode
  if (!this.isMultiSelectMode) {
    this.clearSelection();
    this.cleanupSelectionArtifacts();
  }
});
```

