  const convs = dragData.conversations ?? [];
  const singleId = dragData.conversationId;
  const sourceFolderId = dragData.sourceFolderId;

  // Check if conversation(s) are from outside any folder (native sidebar drag)
  const isFromOutsideFolder = !sourceFolderId;

  if (isFromOutsideFolder) {
    // Add to folder first (via the standard add path)
    if (convs.length > 0) {
      this.addConversationsToFolder(parentId, convs, undefined);
    } else if (singleId) {
      this.addConversationToFolder(parentId, dragData);
    }
  } else if (convs.length > 0) {
    this.reorderOrMoveConversations(
      convs.map((c) => c.conversationId),
      sourceFolderId,
      parentId,
      insertIndex,
    );
  } else if (singleId) {
    this.reorderOrMoveConversations(
      [singleId],
      sourceFolderId,
      parentId,
      insertIndex,
    );
  }
}

