      const textEl = this.batchDeleteProgressElement.querySelector(
        '.gv-batch-delete-progress-text',
      );
      if (textEl) {
        textEl.textContent = this.t('batch_delete_in_progress')
          .replace('{current}', String(current))
          .replace('{total}', String(total));
