  private async getCloudUploadTooltip(): Promise<string> {
    try {
      const response = (await browser.runtime.sendMessage({ type: 'gv.sync.getState' })) as
        | { ok?: boolean; state?: { lastUploadTime?: number | null } }
        | undefined;
      if (response?.ok && response.state) {
