          ? `${baseTooltip}\n${this.t('lastUploaded').replace('{time}', timeStr)}`
          : `${baseTooltip}\n${this.t('neverUploaded')}`;
      }
    } catch (e) {
      console.warn('[FolderManager] Failed to get sync state for tooltip:', e);
    }
    return this.t('folder_cloud_upload');
  }

